  "title": "प्रोविजन्ड बनाम ऑन-डिमांड कैपेसिटी",
  "group": "DynamoDB",
  "options": [
    {
      "text": "प्रोविजन्ड हमेशा बेहतर होता है"
    },
    {
      "text": "ऑन-डिमांड में असीमित क्षमता होती है"
    },
    {
      "text": "दोनों का प्रदर्शन बिल्कुल समान होता है"
    },
    {
      "text": "अनपेक्षित वर्कलोड के लिए ऑन-डिमांड सस्ता पड़ता है"
    }
  ],
  "questionProse": [
    "DynamoDB ऑन-डिमांड कैपेसिटी का इस्तेमाल आपको कब करना चाहिए?"
  ],
  "explanationProse": [
    "ऑन-डिमांड क्षमता तब सबसे अच्छी काम करती है जब:\n  - आपके वर्कलोड अनपेक्षित हों\n  - ट्रैफ़िक अचानक बढ़े या घटे\n  - एप्लिकेशन के एक्सेस पैटर्न अभी स्पष्ट न हों\n  - आप ओवर-प्रोविजनिंग और अनावश्यक खर्च से बचना चाहते हों\n\n  वहीं, प्रोविजन्ड क्षमता तब बेहतर विकल्प है जब:\n  - वर्कलोड अनुमानित और स्थिर हों\n  - आपको प्रदर्शन पर सख्त नियंत्रण चाहिए हो\n  - आप लंबी अवधि में लागत बचाना चाहते हों\n\n  [DynamoDB Capacity Modes](https://aws.amazon.com/dynamodb/pricing/)"
  ]
}
